#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int N, K;
    scanf("%d %d", &N, &K);
    int shelf1[N], shelf2[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &shelf1[i]);
    }
    for (int i = 0; i < N; i++) {
        scanf("%d", &shelf2[i]);
    }
    qsort(shelf1, N, sizeof(int), compare);
    qsort(shelf2, N, sizeof(int), compare);
    int minSkew = shelf1[N-1] + shelf2[N-1];
    for (int i = 0; i <= K; i++) {
        int tempSkew = shelf1[N-1-i] + shelf2[N-1-(K-i)];
        if (tempSkew < minSkew) {
            minSkew = tempSkew;
        }
    }
    printf("%d\n", minSkew);
    return 0;
}

