public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int K = sc.nextInt();
        int[] shelf1 = new int[N];
        int[] shelf2 = new int[N];
        for (int i = 0; i < N; i++) {
            shelf1[i] = sc.nextInt();
        }
        for (int i = 0; i < N; i++) {
            shelf2[i] = sc.nextInt();
        }
        Arrays.sort(shelf1);
        Arrays.sort(shelf2);
        int minSkew = shelf1[N-1] + shelf2[N-1];
        for (int i = 0; i <= K; i++) {
            int tempSkew = shelf1[N-1-i] + shelf2[N-1-(K-i)];
            if (tempSkew < minSkew) {
                minSkew = tempSkew;
            }
        }
        System.out.println(minSkew);
